def check_permission(user, action, resource):
    # Owner always has full access
    if user.user_id == resource.owner_id:
        return True

    # Define role hierarchy
    hierarchy = {'admin': 4, 'manager': 3, 'editor': 2, 'viewer': 1}
    user_level = hierarchy.get(user.role, 0)

    if user_level == 0:
        return False

    # Min level required per action
    action_levels = {'view': 1, 'edit': 2, 'delete': 3}
    required = action_levels.get(action, 0)

    return user_level >= required
